function createSession(title="New conversation"){return{id:crypto.randomUUID?.()||`s-${Date.now()}-${Math.random()}`,title,createdAt:Date.now(),updatedAt:Date.now(),messages:[]}}
function loadSessions(){const saved=loadJson(STORAGE_KEYS.sessions,[]);if(Array.isArray(saved)&&saved.length)return saved;const first=createSession();localStorage.setItem(STORAGE_KEYS.sessions,JSON.stringify([first]));return[first]}
function loadActiveSessionId(){const id=localStorage.getItem(STORAGE_KEYS.activeSession);if(sessions.some(s=>s.id===id))return id;localStorage.setItem(STORAGE_KEYS.activeSession,sessions[0].id);return sessions[0].id}
function getActiveSession(){let s=sessions.find(x=>x.id===activeSessionId);if(!s){s=createSession();sessions.unshift(s);activeSessionId=s.id;saveSessions()}return s}
function getActiveHistory(){return getActiveSession().messages}
function saveSessions(){localStorage.setItem(STORAGE_KEYS.sessions,JSON.stringify(sessions));localStorage.setItem(STORAGE_KEYS.activeSession,activeSessionId)}
