function dateKey(){const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}-${String(d.getDate()).padStart(2,"0")}`}
function trackAnalytics(category,key,amount=1){if(!analytics[category]||typeof analytics[category]!=="object")return;if(typeof analytics[category][key]!=="number")analytics[category][key]=0;analytics[category][key]+=amount;const k=dateKey();analytics.dailyActivity[k]??={messages:0,tools:0,voice:0,files:0};if(category==="totals"&&key==="messagesSent")analytics.dailyActivity[k].messages+=amount;if(category==="tools")analytics.dailyActivity[k].tools+=amount;if(category==="totals"&&["voiceInputs","speechOutputs"].includes(key))analytics.dailyActivity[k].voice+=amount;if(category==="totals"&&key==="filesUploaded")analytics.dailyActivity[k].files+=amount;saveAnalytics()}

