function addMessage(sender,response,save=true,timestamp=Date.now()){
  const n=normalizeResponse(response),text=n.text,row=document.createElement("div");row.className=`message-row ${sender}`;row.dataset.messageText=text.toLowerCase();
  const bubble=document.createElement("article");bubble.className="message";if(sender==="assistant"&&n.type!=="text")bubble.classList.add("rich-message");
  const header=document.createElement("div");header.className="message-header";header.innerHTML=`<span>${sender==="user"?"You":"Smart AI"}</span><span>${getTimeLabel(timestamp)}</span>`;
  const body=document.createElement("div");body.className="message-body";if(sender==="assistant"&&n.type!=="text")body.appendChild(createRichResponseCard(n));else body.textContent=text;
  bubble.append(header,body);row.appendChild(bubble);chatMessages.appendChild(row);chatMessages.scrollTop=chatMessages.scrollHeight;
  if(save){history.push({sender,text,responseType:n.type,responseData:n.data||null,timestamp});const s=getActiveSession();if(sender==="user"&&s.title==="New conversation")s.title=generateSessionTitle(text);saveHistory()}
  if(sender==="assistant")lastAssistantResponse=text;if(historySearchInput.value.trim())searchConversation()
}
