function getRichCardIcon(type){return{weather:'<svg viewBox="0 0 24 24"><circle cx="12" cy="12" r="4"/><path d="M12 2v2M12 20v2M2 12h2M20 12h2M4.9 4.9l1.4 1.4M17.7 17.7l1.4 1.4M4.9 19.1l1.4-1.4M17.7 6.3l1.4-1.4"/></svg>',dictionary:'<svg viewBox="0 0 24 24"><path d="M4 5.5A2.5 2.5 0 0 1 6.5 3H11v16H6.5A2.5 2.5 0 0 0 4 21.5zM20 5.5A2.5 2.5 0 0 0 17.5 3H13v16h4.5A2.5 2.5 0 0 1 20 21.5z"/></svg>',wikipedia:'<svg viewBox="0 0 24 24"><path d="M3 5h4M17 5h4M5 5l4.5 14M19 5l-4.5 14M9.5 19L12 11l2.5 8"/></svg>'}[type]||""}
function createRichResponseCard(r){if(r.type==="weather")return createWeatherCard(r.data);if(r.type==="dictionary")return createDictionaryCard(r.data);if(r.type==="wikipedia")return createWikipediaCard(r.data);const d=document.createElement("div");d.textContent=r.text;return d}
function createWeatherCard(d){const card=document.createElement("section");card.className="rich-card weather-card";card.innerHTML=`<div class="rich-card-header"><div class="rich-card-title"><h3>${escapeHtml(d.place)}</h3><p>${escapeHtml(d.description||"Current conditions")}</p></div><div class="rich-card-icon">${getRichCardIcon("weather")}</div></div><div class="rich-card-grid">${[["Temperature",`${d.temperature}°F`],["Feels like",`${d.feelsLike}°F`],["Humidity",`${d.humidity}%`],["Wind speed",`${d.windSpeed} mph`]].map(x=>`<div class="rich-card-stat"><span>${x[0]}</span><strong>${escapeHtml(x[1])}</strong></div>`).join("")}</div>`;return card}
function createDictionaryCard(d){const card=document.createElement("section");card.className="rich-card dictionary-card";card.innerHTML=`<div class="rich-card-header"><div class="rich-card-title"><h3>${escapeHtml(d.word)}</h3><p>${escapeHtml(d.partOfSpeech||"Definition")}</p></div><div class="rich-card-icon">${getRichCardIcon("dictionary")}</div></div><div class="rich-card-body">${escapeHtml(d.definition)}</div>`;if(d.example){const e=document.createElement("div");e.className="dictionary-example";e.textContent=`“${d.example}”`;card.appendChild(e)}if(d.sourceUrl){const f=document.createElement("div");f.className="rich-card-footer";const a=document.createElement("a");a.className="rich-card-link";a.href=d.sourceUrl;a.target="_blank";a.rel="noopener noreferrer";a.textContent="View source";f.appendChild(a);card.appendChild(f)}return card}
function createWikipediaCard(d){const card=document.createElement("section");card.className="rich-card wikipedia-card";if(d.thumbnail){const i=document.createElement("img");i.className="wikipedia-thumbnail";i.src=d.thumbnail;i.alt=d.title;i.loading="lazy";card.appendChild(i)}const h=document.createElement("div");h.className="rich-card-header";h.innerHTML=`<div class="rich-card-title"><h3>${escapeHtml(d.title)}</h3><p>${escapeHtml(d.description||"Wikipedia")}</p></div><div class="rich-card-icon">${getRichCardIcon("wikipedia")}</div>`;const b=document.createElement("div");b.className="rich-card-body";b.textContent=d.extract;card.append(h,b);if(d.articleUrl){const f=document.createElement("div");f.className="rich-card-footer";const a=document.createElement("a");a.className="rich-card-link";a.href=d.articleUrl;a.target="_blank";a.rel="noopener noreferrer";a.textContent="Read full article";f.appendChild(a);card.appendChild(f)}return card}

