function chooseSuggestions(m){m=m.toLowerCase();if(m.includes("my name is")||m.includes("favorite color")||m.includes("i work as"))return SUGGESTION_SETS.profile;if(m.startsWith("calculate")||m.startsWith("solve")||m.includes("percent of"))return SUGGESTION_SETS.calculator;if(m.startsWith("define")||m.startsWith("wiki")||m.startsWith("tell me about")||m.startsWith("who is"))return SUGGESTION_SETS.learning;return SUGGESTION_SETS.general}
