function responseDelay(text){const m={fast:[100,1,250],normal:[350,4,850],relaxed:[650,7,1500]}[settings.responseSpeed]||[350,4,850];return m[0]+Math.min(text.length*m[1],m[2])}
function safelyCalculate(expr){const n=expr.replace(/\^/g,"**").trim();if(!/^[0-9+\-*/%().\s*]+$/.test(n))throw Error("Unsupported");const result=Function(`"use strict";return(${n})`)();if(typeof result!=="number"||!Number.isFinite(result))throw Error("Invalid");return result}

async function getDefinition(word){setStatus("Looking up definition...");try{const r=await fetch(`https://api.dictionaryapi.dev/api/v2/entries/en/${encodeURIComponent(word)}`);if(!r.ok)throw Error();const data=await r.json(),entry=data[0],meaning=entry?.meanings?.[0],def=meaning?.definitions?.[0];if(!def?.definition)throw Error();return{type:"dictionary",text:`${entry.word} (${meaning.partOfSpeech||"definition"}): ${def.definition}`,data:{word:entry.word,partOfSpeech:meaning.partOfSpeech||"Definition",definition:def.definition,example:def.example||"",sourceUrl:entry.sourceUrls?.[0]||""}}}catch{return{type:"text",text:`I could not find a definition for “${word}.”`}}}
async function getWikipediaSummary(topic){setStatus("Searching Wikipedia...");try{const r=await fetch(`https://en.wikipedia.org/api/rest_v1/page/summary/${encodeURIComponent(topic)}`);if(!r.ok)throw Error();const d=await r.json();if(!d.extract)throw Error();return{type:"wikipedia",text:d.extract,data:{title:d.title||topic,description:d.description||"Wikipedia",extract:d.extract,thumbnail:d.thumbnail?.source||"",articleUrl:d.content_urls?.desktop?.page||""}}}catch{return{type:"text",text:`I could not find a Wikipedia summary for “${topic}.”`}}}
function normalizeLocation(v){return v.toLowerCase().replace(/\./g,"").replace(/\s+/g," ").trim()}
function parseCityState(text){const clean=text.replace(/[?.!]+$/,"").trim(),parts=clean.split(",").map(x=>x.trim()).filter(Boolean);if(parts.length>=2)return{city:parts[0],state:parts.slice(1).join(" ")};const words=clean.split(/\s+/),abbr=words.at(-1)?.toUpperCase();return abbr&&US_STATES[abbr]?{city:words.slice(0,-1).join(" "),state:US_STATES[abbr]}:{city:clean,state:""}}
async function geocodeCity(text){const{city,state}=parseCityState(text),r=await fetch(`https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(city)}&count=10&language=en&format=json`);if(!r.ok)throw Error();const results=(await r.json()).results||[];if(!results.length)throw Error();if(!state)return results[0];const wanted=normalizeLocation(US_STATES[state.toUpperCase()]||state);return results.find(x=>(x.country_code||"").toUpperCase()==="US"&&normalizeLocation(x.admin1||"")===wanted)||results[0]}
function weatherDescription(code){return({0:"clear skies",1:"mostly clear skies",2:"partly cloudy",3:"overcast",45:"fog",48:"freezing fog",51:"light drizzle",53:"moderate drizzle",55:"heavy drizzle",61:"light rain",63:"moderate rain",65:"heavy rain",71:"light snow",73:"moderate snow",75:"heavy snow",80:"light rain showers",81:"moderate rain showers",82:"heavy rain showers",95:"thunderstorms",96:"thunderstorms with hail",99:"severe thunderstorms with hail"})[code]||"current conditions"}
async function getWeather(locationText){setStatus("Checking weather...");try{const loc=await geocodeCity(locationText),r=await fetch(`https://api.open-meteo.com/v1/forecast?latitude=${loc.latitude}&longitude=${loc.longitude}&current=temperature_2m,apparent_temperature,relative_humidity_2m,weather_code,wind_speed_10m&temperature_unit=fahrenheit&wind_speed_unit=mph&timezone=auto`);if(!r.ok)throw Error();const c=(await r.json()).current;if(!c)throw Error();const place=[loc.name,loc.admin1,loc.country].filter(Boolean).join(", "),desc=weatherDescription(c.weather_code);return{type:"weather",text:`Weather for ${place}: ${c.temperature_2m}°F with ${desc}. Feels like ${c.apparent_temperature}°F. Humidity ${c.relative_humidity_2m}% and wind ${c.wind_speed_10m} mph.`,data:{place,temperature:c.temperature_2m,feelsLike:c.apparent_temperature,humidity:c.relative_humidity_2m,windSpeed:c.wind_speed_10m,weatherCode:c.weather_code,description:desc}}}catch{return{type:"text",text:`I could not retrieve weather information for “${locationText}.” Try a city and state.`}}}
function extractWeatherLocation(text){for(const p of [/^weather\s+(?:in\s+)?(.+)$/i,/^what(?:'s| is)\s+the\s+weather\s+(?:like\s+)?(?:in|for)\s+(.+)$/i,/^how(?:'s| is)\s+the\s+weather\s+(?:in|for)\s+(.+)$/i,/^(?:tell me|check)\s+the\s+weather\s+(?:in|for)\s+(.+)$/i]){const m=text.match(p);if(m?.[1])return m[1].replace(/[?.!]+$/,"").trim()}return""}

