function updateAiInterface(){const mode=settings.assistantMode||"built-in";builtInModeRadio.checked=mode==="built-in";localAiModeRadio.checked=mode==="local-ai";cloudAiModeRadio.checked=false;loadAiModelButton.disabled=aiModelLoading||aiModelReady;unloadAiModelButton.disabled=!aiModelReady||aiModelLoading;if(aiModelLoading){aiModeBadge.textContent="Local AI Loading";aiModeBadge.className="ai-mode-badge loading";localAiAvailability.textContent="Loading model…";return}if(mode==="local-ai"&&aiModelReady&&aiEngine){aiModeBadge.textContent="Local AI";aiModeBadge.className="ai-mode-badge ready";localAiAvailability.textContent="Model ready";localAiAvailability.className="mode-availability ready";aiModelStatus.textContent="Local AI is active. Built-in tools remain available.";return}aiModeBadge.textContent="Built-in Tools";aiModeBadge.className="ai-mode-badge";localAiAvailability.textContent=aiModelReady?"Model loaded":"Model not loaded";localAiAvailability.className=aiModelReady?"mode-availability ready":"mode-availability";aiModelStatus.textContent=aiModelReady?"The Local AI model is loaded but Built-in Tools are active.":"Built-in Tools are active."}
async function loadAiModel(){if(aiModelReady&&aiEngine){settings.assistantMode="local-ai";saveSettings();updateAiInterface();return}if(aiModelLoading)return;if(!supportsWebGPU()){setStatus("WebGPU unavailable");return}aiModelLoading=true;settings.assistantMode="built-in";saveSettings();aiProgressContainer.hidden=false;aiProgressBar.style.width="0%";setStatus("Loading Local AI model...");setAvatarState("loading-ai");updateAiInterface();try{aiEngine=await CreateMLCEngine(AI_MODEL_ID,{initProgressCallback:p=>{const pct=Math.max(0,Math.min(100,Math.round(Number(p.progress||0)*100)));aiProgressBar.style.width=`${pct}%`;aiProgressText.textContent=p.text||`Loading model: ${pct}%`;aiModelStatus.textContent=p.text||"Downloading and preparing model…"}});if(!aiEngine)throw Error("No engine");aiModelReady=true;aiModelLoading=false;settings.assistantMode="local-ai";saveSettings();trackAnalytics("assistantModes","local-ai");aiProgressBar.style.width="100%";aiProgressText.textContent="Model ready";setStatus("Local AI ready");setAvatarState("idle");updateAiInterface()}catch(e){console.error(e);aiEngine=null;aiModelReady=false;aiModelLoading=false;settings.assistantMode="built-in";saveSettings();aiProgressContainer.hidden=true;setStatus("Local AI model error");setAvatarState("idle");updateAiInterface()}}
async function unloadAiModel(){if(aiModelLoading)return setStatus("AI model is still loading");setStatus("Unloading Local AI...");if(aiEngine){try{if(typeof aiEngine.unload==="function")await aiEngine.unload();else if(typeof aiEngine.resetChat==="function")await aiEngine.resetChat()}catch(e){console.warn(e)}}aiEngine=null;aiModelReady=false;aiModelLoading=false;settings.assistantMode="built-in";saveSettings();aiProgressContainer.hidden=true;aiProgressBar.style.width="0%";aiProgressText.textContent="Preparing model…";setAvatarState("idle");updateAiInterface();setStatus("Ready")}
function buildAiMessages(input){const system={role:"system",content:`You are Smart Assistant AI, a concise portfolio assistant. Saved name: ${profile.name||"unknown"}. Favorite color: ${profile.favoriteColor||"unknown"}. Occupation: ${profile.job||"unknown"}.`},recent=history.slice(-10).map(x=>({role:x.sender==="user"?"user":"assistant",content:x.text}));if(recent.at(-1)?.content!==input)recent.push({role:"user",content:input});return[system,...recent]}
async function getAiResponse(input){setStatus("Local AI thinking...");try{const c=await aiEngine.chat.completions.create({messages:buildAiMessages(input),temperature:.7,max_tokens:350}),text=c?.choices?.[0]?.message?.content?.trim();if(!text)throw Error();return text}catch(e){console.error(e);return"The local AI model could not complete that response. Please retry."}}

async function processMessage(input){
 const original=input.trim(),m=original.toLowerCase();if(!m)return"Please enter a message.";
 if(["hi","hello","hey"].includes(m))return profile.name?`Hello, ${profile.name}! How can I help?`:"Hello! How can I help?";
 if(m.includes("my name is")){trackAnalytics("tools","memory");const v=cleanValue(original.substring(m.indexOf("my name is")+10));if(!v)return"Tell me the name to remember.";profile.name=titleCase(v);saveProfile();return`Nice to meet you, ${profile.name}! I will remember your name.`}
 if(m.includes("what is my name")||m.includes("what's my name")){trackAnalytics("tools","memory");return profile.name?`Your name is ${profile.name}.`:"I do not know your name yet."}
 if(m.includes("my favorite color is")){trackAnalytics("tools","memory");const v=cleanValue(original.substring(m.indexOf("my favorite color is")+20));profile.favoriteColor=titleCase(v);saveProfile();return`I’ll remember that your favorite color is ${profile.favoriteColor}.`}
 if(m.includes("what is my favorite color")||m.includes("what's my favorite color")){trackAnalytics("tools","memory");return profile.favoriteColor?`Your favorite color is ${profile.favoriteColor}.`:"I do not know your favorite color yet."}
 if(m.includes("i work as")||m.includes("i am a")){trackAnalytics("tools","memory");const phrase=m.includes("i work as")?"i work as":"i am a",v=cleanValue(original.substring(m.indexOf(phrase)+phrase.length));profile.job=titleCase(v);saveProfile();return`I’ll remember that you work as a ${profile.job}.`}
 if(m.includes("what do i do")||m.includes("what is my job")||m.includes("what's my job")){trackAnalytics("tools","memory");return profile.job?`You told me that you work as a ${profile.job}.`:"I do not know your occupation yet."}
 if(m.startsWith("calculate ")||m.startsWith("solve ")){trackAnalytics("tools","calculator");const cmd=m.startsWith("calculate ")?"calculate":"solve",expr=original.substring(cmd.length).trim();try{return`${expr} = ${safelyCalculate(expr)}`}catch{return"I could not calculate that expression."}}
 if(m.includes("percent of")||m.includes("% of")){trackAnalytics("tools","percentage");const x=m.match(/(-?\d+(?:\.\d+)?)\s*(?:percent|%)\s+of\s+(-?\d+(?:\.\d+)?)/);return x?`${x[1]}% of ${x[2]} = ${(Number(x[1])/100)*Number(x[2])}`:"Try: 15 percent of 300."}
 if(m.startsWith("define ")){trackAnalytics("tools","dictionary");return await getDefinition(original.substring(7).trim())}
 if(m.startsWith("wiki ")||m.startsWith("tell me about ")||m.startsWith("who is ")){trackAnalytics("tools","wikipedia");const topic=m.startsWith("wiki ")?original.substring(5):m.startsWith("tell me about ")?original.substring(14):original.substring(7);return await getWikipediaSummary(topic.trim())}
 if(m.includes("weather")){trackAnalytics("tools","weather");const loc=extractWeatherLocation(original);return loc?await getWeather(loc):"Tell me the city and state, such as Philadelphia, PA."}
 if(m.includes("joke")||m.includes("make me laugh")){trackAnalytics("tools","jokes");const j=jokes[Math.floor(Math.random()*jokes.length)];return`${j[0]}\n${j[1]}`}
 if(m.includes("what time")||m==="time"){trackAnalytics("tools","dateTime");return`The current time is ${new Date().toLocaleTimeString([],{hour:"numeric",minute:"2-digit"})}.`}
 if(m.includes("what is today's date")||m.includes("what is the date")||m==="date"){trackAnalytics("tools","dateTime");return`Today is ${new Date().toLocaleDateString([],{weekday:"long",year:"numeric",month:"long",day:"numeric"})}.`}
 if(m.includes("what can you do"))return"I can remember your profile, calculate, define words, search Wikipedia, check weather, accept voice input, speak responses, manage conversations, analyze CSV/JSON files, generate charts, provide local analytics, and optionally use Local AI.";
 if(settings.assistantMode==="local-ai"&&aiModelReady&&aiEngine){trackAnalytics("tools","localAi");return await getAiResponse(original)}
 return"I’m still learning that command. Try a built-in tool or load Local AI in Settings for open-ended questions.";
}
async function sendMessage(command=null){const input=typeof command==="string"?command:messageInput.value.trim();if(!input||messageInput.disabled)return;trackAnalytics("totals","messagesSent");addMessage("user",input);messageInput.value="";setStatus("Thinking...");setAvatarState("thinking");setComposerDisabled(true);showTypingIndicator();try{const response=await processMessage(input),text=getResponseText(response),delay=responseDelay(text);setTimeout(()=>{removeTypingIndicator();addMessage("assistant",response);trackAnalytics("totals","assistantResponses");setAvatarState("idle");renderSuggestions(chooseSuggestions(input));setComposerDisabled(false);messageInput.focus();if(settings.autoSpeak)speakResponse(text);else setStatus("Ready")},delay)}catch(e){console.error(e);removeTypingIndicator();addMessage("assistant","Something went wrong.");setAvatarState("idle");setComposerDisabled(false);setStatus("Error")}}

function speakResponse(text){if(!text||!("speechSynthesis"in window))return;speechSynthesis.cancel();const s=new SpeechSynthesisUtterance(text);s.onstart=()=>{setStatus("Speaking...");setAvatarState("speaking");trackAnalytics("totals","speechOutputs")};s.onend=()=>{setStatus("Ready");setAvatarState("idle")};s.onerror=()=>{setStatus("Speech error");setAvatarState("idle")};speechSynthesis.speak(s)}
function speakLastResponse(){if(lastAssistantResponse)speakResponse(lastAssistantResponse);else setStatus("No response to read")}
function initializeSpeechRecognition(){const SR=window.SpeechRecognition||window.webkitSpeechRecognition;if(!SR){microphoneButton.disabled=true;return}speechRecognition=new SR();speechRecognition.lang="en-US";speechRecognition.interimResults=true;speechRecognition.onstart=()=>{isListening=true;microphoneButton.classList.add("listening");microphoneButton.textContent="⏹";setStatus("Listening...");setAvatarState("listening");trackAnalytics("totals","voiceInputs")};speechRecognition.onresult=e=>{let t="";for(let i=e.resultIndex;i<e.results.length;i++)t+=e.results[i][0].transcript;messageInput.value=t.trim()};speechRecognition.onerror=e=>{console.error(e);setStatus("Voice input error");setAvatarState("idle")};speechRecognition.onend=()=>{isListening=false;microphoneButton.classList.remove("listening");microphoneButton.textContent="🎤";setStatus(messageInput.value.trim()?"Voice captured":"Ready");setAvatarState("idle")}}
function toggleVoiceInput(){if(!speechRecognition)return setStatus("Voice input unavailable");if(isListening)return speechRecognition.stop();messageInput.value="";try{speechRecognition.start()}catch{setStatus("Could not start microphone")}}

function generateSessionTitle(t){t=t.replace(/\s+/g," ").trim();return t.length<=32?t:`${t.slice(0,32).trim()}…`}
function formatSessionDate(ts){const d=new Date(ts),today=new Date();return d.toDateString()===today.toDateString()?d.toLocaleTimeString([],{hour:"numeric",minute:"2-digit"}):d.toLocaleDateString([],{month:"short",day:"numeric"})}
function renderConversationList(){conversationList.innerHTML="";for(const s of [...sessions].sort((a,b)=>b.updatedAt-a.updatedAt)){const item=document.createElement("div");item.className=`conversation-item${s.id===activeSessionId?" active":""}`;const select=document.createElement("button");select.className="conversation-select";select.type="button";select.innerHTML=`<span class="conversation-title">${escapeHtml(s.title)}</span><span class="conversation-date">${formatSessionDate(s.updatedAt)}</span>`;select.onclick=()=>switchSession(s.id);const menu=document.createElement("div");menu.className="conversation-menu";const mb=document.createElement("button");mb.type="button";mb.className="conversation-menu-button";mb.textContent="⋯";const opts=document.createElement("div");opts.className="conversation-menu-options";const rb=document.createElement("button");rb.textContent="Rename";rb.onclick=e=>{e.stopPropagation();renameSession(s.id)};const db=document.createElement("button");db.textContent="Delete";db.className="delete-session-button";db.onclick=e=>{e.stopPropagation();deleteSession(s.id)};mb.onclick=e=>{e.stopPropagation();menu.classList.toggle("open")};opts.append(rb,db);menu.append(mb,opts);item.append(select,menu);conversationList.appendChild(item)}}
function startNewConversation(){const s=createSession();sessions.unshift(s);activeSessionId=s.id;history=s.messages;saveSessions();renderHistory();renderConversationList();clearConversationSearch();trackAnalytics("totals","conversationsCreated")}
function switchSession(id){activeSessionId=id;history=getActiveHistory();saveSessions();renderHistory();renderConversationList();clearConversationSearch()}
function renameSession(id){const s=sessions.find(x=>x.id===id),t=prompt("Rename conversation:",s?.title);if(s&&t?.trim()){s.title=t.trim();s.updatedAt=Date.now();saveSessions();renderConversationList()}}
function deleteSession(id){const s=sessions.find(x=>x.id===id);if(!s||!confirm(`Delete “${s.title}”?`))return;sessions=sessions.filter(x=>x.id!==id);if(!sessions.length)sessions=[createSession()];if(activeSessionId===id)activeSessionId=sessions[0].id;history=getActiveHistory();saveSessions();renderHistory();renderConversationList()}
