function clearMemory(){if(!confirm("Clear saved profile memory?"))return;profile={};localStorage.removeItem(STORAGE_KEYS.profile);updateProfileDisplay();renderMemorySummary();addMessage("assistant","Your saved profile memory has been cleared.")}
function exportChat(){if(!history.length)return setStatus("No chat to export");const text=history.map(x=>`${x.sender==="user"?"You":"Smart AI"}: ${x.text}`).join("\n\n"),blob=new Blob([text],{type:"text/plain"}),url=URL.createObjectURL(blob),a=document.createElement("a");a.href=url;a.download=`${generateSessionTitle(getActiveSession().title).replace(/[^a-z0-9]+/gi,"-").toLowerCase()}.txt`;a.click();URL.revokeObjectURL(url);trackAnalytics("totals","exports")}

function escapeRegex(v){return v.replace(/[.*+?^${}()|[\]\\]/g,"\\$&")}
function clearSearchHighlights(){document.querySelectorAll(".message-row").forEach(r=>{r.classList.remove("search-hidden","search-match","search-active");const b=r.querySelector(".message-body");if(b?.dataset.originalText){b.textContent=b.dataset.originalText;delete b.dataset.originalText}})}
function searchConversation(){const q=historySearchInput.value.trim().toLowerCase();clearSearchHighlights();searchMatches=[];activeSearchIndex=-1;if(!q)return updateSearchControls();for(const r of chatMessages.querySelectorAll(".message-row:not(#typingIndicatorRow)")){const match=(r.dataset.messageText||"").includes(q);r.classList.toggle("search-hidden",!match);if(match){r.classList.add("search-match");searchMatches.push(r)}}if(searchMatches.length)activateSearchResult(0);else updateSearchControls()}
