async function handleSelectedFile(file){if(!file)return;const ext=file.name.split(".").pop().toLowerCase();if(!["csv","json"].includes(ext))return setStatus("Only CSV and JSON are supported");setStatus("Reading file...");setAvatarState("thinking");try{let rows=ext==="csv"?await new Promise((resolve,reject)=>Papa.parse(file,{header:true,dynamicTyping:true,skipEmptyLines:true,worker:true,complete:r=>resolve(r.data),error:reject})):await parseJsonFile(file);rows=rows.filter(x=>x&&typeof x==="object"&&!Array.isArray(x));if(!rows.length)throw Error("No usable rows");uploadedFile=file;uploadedRows=rows;uploadedColumns=Object.keys(rows[0]);renderFileWorkspace();trackAnalytics("totals","filesUploaded");trackAnalytics("tools","fileAnalyzer");trackAnalytics("fileTypes",ext);setStatus("File loaded")}catch(e){console.error(e);setStatus(e.message||"Could not read file")}finally{setAvatarState("idle")}}
async function parseJsonFile(file){const p=JSON.parse(await file.text());if(Array.isArray(p))return p;if(p&&typeof p==="object"){const a=Object.values(p).find(Array.isArray);return a||[p]}throw Error("Unsupported JSON")}
function getNumericColumns(){return uploadedColumns.filter(c=>{const vals=uploadedRows.map(r=>r[c]).filter(v=>v!==""&&v!=null);return vals.length&&vals.filter(v=>Number.isFinite(Number(v))).length/vals.length>=.8})}
