function renderFileWorkspace(){fileDropZone.hidden=true;fileWorkspace.hidden=false;loadedFileName.textContent=uploadedFile.name;const nums=getNumericColumns(),missing=uploadedRows.reduce((t,r)=>t+uploadedColumns.filter(c=>r[c]===""||r[c]==null).length,0);fileStats.innerHTML=[["Rows",uploadedRows.length],["Columns",uploadedColumns.length],["Numeric columns",nums.length],["Missing values",missing]].map(x=>`<div class="file-stat-card"><span>${x[0]}</span><strong>${x[1]}</strong></div>`).join("");populateSelect(labelColumnSelect,uploadedColumns);populateSelect(valueColumnSelect,nums);populateSelect(secondaryValueSelect,nums);generateChartButton.disabled=!nums.length;renderDataPreview();updateChartControlVisibility();chartContainer.hidden=true;if(activeDataChart){activeDataChart.destroy();activeDataChart=null}}
function renderDataPreview(){const rows=uploadedRows.slice(0,25),head=dataPreviewTable.querySelector("thead"),body=dataPreviewTable.querySelector("tbody");head.innerHTML=`<tr>${uploadedColumns.map(c=>`<th>${escapeHtml(c)}</th>`).join("")}</tr>`;body.innerHTML=rows.map(r=>`<tr>${uploadedColumns.map(c=>`<td>${escapeHtml(r[c]??"")}</td>`).join("")}</tr>`).join("");previewRowCount.textContent=`${rows.length} of ${uploadedRows.length} rows`}
