function generateDataChart(){const type=chartTypeSelect.value,label=labelColumnSelect.value,value=valueColumnSelect.value,rows=uploadedRows.slice(0,50);if(!value)return;if(activeDataChart)activeDataChart.destroy();let data,options={responsive:true,maintainAspectRatio:false};if(type==="scatter"){const y=secondaryValueSelect.value;data={datasets:[{label:`${value} vs ${y}`,data:rows.map(r=>({x:Number(r[value]),y:Number(r[y])})).filter(p=>Number.isFinite(p.x)&&Number.isFinite(p.y))}]};options.scales={x:{title:{display:true,text:value}},y:{title:{display:true,text:y}}}}else data={labels:rows.map(r=>String(r[label])),datasets:[{label:value,data:rows.map(r=>Number(r[value]))}]};activeDataChart=new Chart(chartCanvas,{type,data,options});chartContainer.hidden=false;trackAnalytics("totals","chartsGenerated");trackAnalytics("chartTypes",type);setStatus("Chart generated")}
function downloadActiveChart(){if(!activeDataChart)return;const a=document.createElement("a");a.href=activeDataChart.toBase64Image();a.download=`${uploadedFile.name.replace(/\.[^.]+$/,"").replace(/[^a-z0-9]+/gi,"-").toLowerCase()}-chart.png`;a.click();trackAnalytics("totals","chartsDownloaded")}
