function renderAnalyticsDashboard(){renderAnalyticsMetrics();renderList(assistantModeAnalytics,[["Built-in Tools",analytics.assistantModes["built-in"]],["Local AI",analytics.assistantModes["local-ai"]]]);renderList(themeAnalytics,Object.entries(analytics.themes).map(([k,v])=>[titleCase(k),v]));renderList(fileAnalytics,[["CSV files",analytics.fileTypes.csv],["JSON files",analytics.fileTypes.json],["Charts generated",analytics.totals.chartsGenerated],["Charts downloaded",analytics.totals.chartsDownloaded]]);renderList(voiceAnalytics,[["Voice inputs",analytics.totals.voiceInputs],["Spoken responses",analytics.totals.speechOutputs]]);if(activityTrendChart)activityTrendChart.destroy();const dates=recentDates();activityTrendChart=new Chart(activityTrendCanvas,{type:"line",data:{labels:dates.map(d=>d.label),datasets:[{label:"Messages",data:dates.map(d=>analytics.dailyActivity[d.key]?.messages||0),tension:.3},{label:"Tool requests",data:dates.map(d=>analytics.dailyActivity[d.key]?.tools||0),tension:.3}]},options:{responsive:true,maintainAspectRatio:false,scales:{y:{beginAtZero:true,ticks:{precision:0}}}}});if(toolUsageChart)toolUsageChart.destroy();const entries=Object.entries(analytics.tools).filter(([,v])=>v>0).sort((a,b)=>b[1]-a[1]).slice(0,8);toolUsageChart=new Chart(toolUsageCanvas,{type:"bar",data:{labels:entries.length?entries.map(([k])=>titleCase(k.replace(/([A-Z])/g," $1"))):["No usage"],datasets:[{label:"Requests",data:entries.length?entries.map(([,v])=>v):[0]}]},options:{indexAxis:"y",responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{beginAtZero:true,ticks:{precision:0}}}}});analyticsLastUpdated.textContent=analytics.lastUpdated?`Last updated ${new Date(analytics.lastUpdated).toLocaleString()}`:"Analytics have not been recorded yet."}
