for(const overlay of [settingsOverlay,aboutOverlay,fileOverlay,analyticsOverlay])overlay.onclick=e=>{if(e.target===overlay)closeOverlay(overlay,document.activeElement)};
document.addEventListener("click",()=>document.querySelectorAll(".conversation-menu.open").forEach(x=>x.classList.remove("open")));
document.addEventListener("keydown",e=>{if(e.key!=="Escape")return;if(settingsOverlay.classList.contains("open"))closeOverlay(settingsOverlay,settingsButton);if(aboutOverlay.classList.contains("open"))closeOverlay(aboutOverlay,aboutButton);if(fileOverlay.classList.contains("open"))closeOverlay(fileOverlay,uploadFileButton);if(analyticsOverlay.classList.contains("open"))closeOverlay(analyticsOverlay,analyticsButton)});
document.querySelectorAll("[data-command]").forEach(b=>b.onclick=()=>sendMessage(b.dataset.command));
window.addEventListener("online",updateConnectionStatus);window.addEventListener("offline",updateConnectionStatus);window.addEventListener("beforeinstallprompt",handleInstallPrompt);window.addEventListener("appinstalled",()=>{deferredInstallPrompt=null;installAppButton.hidden=true});

applyTheme(settings.theme);if(localStorage.getItem(STORAGE_KEYS.sidebar)==="collapsed")appShell.classList.add("sidebar-collapsed");if(settings.assistantMode==="local-ai")settings.assistantMode="built-in";saveSettings();updateProfileDisplay();renderMemorySummary();renderHistory();renderConversationList();renderSuggestions(profile.name?SUGGESTION_SETS.profile:SUGGESTION_SETS.onboarding);initializeSpeechRecognition();updateSearchControls();updateConnectionStatus();updateAiInterface();setAvatarState("idle");registerServiceWorker();for(const o of [settingsOverlay,aboutOverlay,fileOverlay,analyticsOverlay])o.inert=true;messageInput.focus();
